function getImg(name, deity, type) {
  if (SPECIFIC[name]) return SPECIFIC[name]
  const d = (deity||'').toLowerCase(), t = (type||'').toLowerCase()
  if (d.includes('jain') || t.includes('jain')) return I.jain
  if (d.includes('shiva') || d.includes('shankar') || d.includes('mahadev')) return I.shiva
  if (d.includes('krishna') || d.includes('jagannath') || d.includes('vithal')) return I.krishna
  if (d.includes('vishnu') || d.includes('rama') || d.includes('venkat') || d.includes('narayan') || d.includes('balaji')) return I.vishnu
  if (d.includes('durga') || d.includes('kali') || d.includes('shakti') || d.includes('devi') || d.includes('lakshmi') || d.includes('amba') || d.includes('chamunda') || d.includes('bhavani') || d.includes('parvati')) return I.shakti
  if (d.includes('ganesha') || d.includes('ganesh') || d.includes('vinayak')) return I.ganesha
  if (d.includes('murugan') || d.includes('subramanya') || d.includes('kartikeya')) return I.murugan
  if (d.includes('hanuman') || d.includes('bajrang')) return I.hanuman
  if (t.includes('cave')) return I.cave
  if (t.includes('hilltop') || t.includes('hill')) return I.hill
  const pool = [I.t1, I.t2, I.t3, I.t4, I.t5]
  return pool[name.charCodeAt(0) % pool.length]
}

