// ══════════════════════════════════════════════════════════════════════
async function main() {
  console.log(`\n🛕 DivyaDarshanam Temple Seed`)
  console.log(`📊 Total temples to seed: ${TEMPLES.length}`)
  console.log(`\n🔗 Connecting to MongoDB...`)

  const client = new MongoClient(MONGODB_URI, { family: 4, serverSelectionTimeoutMS: 15000 })
  await client.connect()
  console.log('✅ Connected!\n')

  const db = client.db()
  const col = db.collection('temples')

  // Create text index
  await col.createIndex(
    { name: 'text', city: 'text', state: 'text', deity: 'text', description: 'text' },
    { weights: { name: 10, deity: 5, city: 4, state: 3 }, name: 'temple_search_v2', background: true }
  ).catch(() => console.log('  (Text index already exists)'))

  let ok = 0, err = 0
  const total = TEMPLES.length

  for (const t of TEMPLES) {
    const sl = slug(t.n)
    const image_url = getImg(t.n, t.de, t.ty)
    try {
      await col.findOneAndUpdate(
        { slug: sl },
        { $set: {
          slug: sl, name: t.n, state: t.st, city: t.ci,
          deity: t.de, type: t.ty, description: t.d,
          festivals: t.f, timing: t.tm, best_time: t.bt,
          dress_code: t.dc, categories: t.cat || [],
          has_live: t.lv || false, live_url: t.lu || '',
          lat: t.lat || null, lng: t.lng || null,
          image_url,
          updatedAt: new Date()
        }, $setOnInsert: { rating_avg: 0, rating_count: 0, createdAt: new Date() }},
        { upsert: true }
      )
      ok++
      if (ok % 50 === 0) console.log(`  ✅ ${ok}/${total} seeded...`)
    } catch(e) {
      console.error(`  ❌ ${t.n}: ${e.message}`)
      err++
    }
  }

  const dbTotal = await col.countDocuments()
  console.log(`\n🎉 SEED COMPLETE!`)
  console.log(`   Processed: ${ok}`)
  console.log(`   Errors:    ${err}`)
  console.log(`   ─────────────────────`)
  console.log(`   Total in DB: ${dbTotal} temples`)
  console.log(`\n   States covered: 25+`)
  console.log(`   Jain temples: 25+`)
  console.log(`   Live streams: ${TEMPLES.filter(t=>t.lv).length}`)

  await client.close()
}

main().catch(e => { console.error('❌ Seed failed:', e.message); process.exit(1) })
